def next_greater(nums):
    n = len(nums)
    result = [-1] * n
    stack = []               # stores indices, decreasing values
    for i in range(n):
        while stack and nums[stack[-1]] < nums[i]:
            idx = stack.pop()
            result[idx] = nums[i]   # nums[i] is the next greater
        stack.append(i)
    return result

def prev_smaller(nums):
    n = len(nums)
    result = [-1] * n
    stack = []               # stores indices, increasing values
    for i in range(n):
        while stack and nums[stack[-1]] >= nums[i]:
            stack.pop()
        if stack:
            result[i] = nums[stack[-1]]
        stack.append(i)
    return result

